var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":"오오, 보면 볼수록 경이로운 광경이야……","JPN":"おお、見れば見るほど脅威的な光景だ……","ENG":"Wow... The more I look at it, the more wondrous it is...","TWN":"喔，真是越看越神奇……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_A","text":{"KOREA":"학회장님께서 손톱만큼 작은 파편이라도 하사해 주시지 않을까?","JPN":"学会長がほんの小さな破片でもいいから与えてくださらないだろうか？","ENG":"I wonder if the President will gift us a very small Fragment of knowledge to us.","TWN":"學會長應該會賞賜給我們指甲那麼大的碎片吧？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_ESPR_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_B","text":{"KOREA":"감상에 빠져 있지 말고 손이나 움직여.","JPN":"感激してないで、手を動かせ。","ENG":"Stop daydreaming and work.","TWN":"別欣賞了，動手吧。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_B","text":{"KOREA":"사진이든 스케치든 기록으로 남길 수 있는 건 뭐든 하라고.","JPN":"写真でもスケッチでも、記録として残せるものは何でも残せ。","ENG":"Create whatever record you can, whether it's a picture or a sketch.","TWN":"不管是照片還是素描，能留作記錄的都要留下。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_ESPR_NULL_B","text":{"KOREA":"뭐야, 왜 대답이……","JPN":"おい、なんで返事を……","ENG":"Huh? Why aren't you ans–","TWN":"幹嘛，怎麼不回答……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_ESPR_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"안녕하신가, 친구.","JPN":"ちょっと失礼するぞ。","ENG":"Hello there.","TWN":"你們好啊，朋友。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"경계가 허술하군요. 다들 넋을 놓고 저 흉물만 구경하기 바쁜 듯합니다.","JPN":"警戒が緩いですね。みなさん、あの気持ち悪いものに目を奪われていて気付かないようです。","ENG":"Do you think their security is lacking? They're all gawking at that monstrosity.","TWN":"警戒很鬆懈啊。大家好像都在忙著看那個怪物呢。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그야 어쩔 수 없지. 학회원들에게는 저 파편이 보물 더미 같을 테니까.","JPN":"それは仕方ない。学会員にとっては、あの破片が宝の山に見えるだろうからな。","ENG":"But what can you do? To the Society members, those Fragment must look like gold.","TWN":"這也是沒辦法的事。因為對於學會成員來說，那個碎片就像一堆寶物。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"게다가 보게나. 허술해 보여도 준비성이 좋은 친구들이야.","JPN":"それに、見ろ。緩く見えても手回しのいいやつらだ。","ENG":"And just look. Although it might seem sloppy, they are well organized.","TWN":"再說了，你看看，他們雖然看起來很鬆懈，但是都有所準備。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"교활한 장수여. 분명 조용히 들어가겠다고 하지 않았던가.","JPN":"狡猾な将軍よ。確か、目立たぬよう侵入すると言っていなかったか？","ENG":"Ye cunning knight. Didn't you say we would go in quietly?","TWN":"狡猾的商人，我分明說過要安靜地進去的。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"작전 목표에 대해 말해 주지 않았나?","JPN":"作戦目標について話しただろう？","ENG":"Didn't I tell you about the operation goal?","TWN":"我沒說過作戰目標嗎？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"집중을 흐트러뜨리는 데에는 앞마당에서 설치는 게 제일이지.","JPN":"集中を乱すには、庭で暴れるのが一番だ。","ENG":"Distracting them in front of them is the most effective method.","TWN":"為了分散注意力，最好在前院安裝。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어때, 아가씨도 그렇게 생각하나?","JPN":"どうだ、お嬢さんもそう思わないか？","ENG":"Don't you feel the same way, Miss?","TWN":"怎麼樣，小姐也是這麼想的嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄. 재빠르게 숨어든 것만은 칭찬해 줄게.","JPN":"どうかしら。素早く忍び込んだのは褒めてあげるわ。","ENG":"Maybe. But I will compliment you on your swift invasion.","TWN":"這個嘛，我只想誇一句，躲得挺快。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 낡아빠진 인간이랑 빈털터리 예하에…… 호라이즌인가.","JPN":"でも、古くさい人間に貧乏猊下に……ホライズンね。","ENG":"But aren't they just one old-fashioned human, a penniless Eminence, and... Horizon?","TWN":"不過殘破的人類和虛有其表的主教……是地平線嗎。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그로니아에 비해서도 너무 단촐하지 않아?","JPN":"グロニアに比べても少なすぎると思わない？","ENG":"Doesn't that seem too small compared to in Gronia?","TWN":"與格羅尼亞相比，是不是太過簡單了？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"냉정하고 객관적인 평가 감사합니다, 그림자.","JPN":"冷静で客観的な評価感謝します、シャドウ。","ENG":"I appreciate your cold and objective assessment, Shadow.","TWN":"謝謝你冷靜又客觀的評價，暗影。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신과는 3회전이군요. 홈런 맞을 준비는 됐습니까?","JPN":"あなたとは3回戦ですね。ホームランを打たれる準備はいいですか？","ENG":"I believe we're on round 3 now? Are you ready to see me hit a home run?","TWN":"這是和你的第三輪較量。你做好被全壘打的準備了嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L28_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"미안하지만 난 야구처럼 떼로 몰려다니는 것보다 귀족적인 테니스가 취향이야.","JPN":"悪いけど、私は野球みたいに群がるスポーツより貴族的なテニスが好みなの。","ENG":"I'm sorry, but tennis takes precedence over baseball in my book.","TWN":"抱歉，不過比起棒球那種一群人到處跑的運動，我更喜歡有貴族氣質的網球。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 꼬인 성격으로는 같이 쳐 줄 상대도 희귀하겠군요.","JPN":"そのひねくれた性格では一緒にプレイしてくれる相手も数少ないでしょう。","ENG":"I'm sure it's difficult to find someone to play tennis with when you have such a twisted personality.","TWN":"以你那種扭曲的性格，願意和你一起打球的人也很少有吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 왜? 네가 있잖아!","JPN":"ふふっ、どうして？　あなたがいるじゃない！","ENG":"Hehe, what do you mean? I have you!","TWN":"呵呵，怎麼了？不是有你嘛！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"카르멘. 타인의 육신을 약탈하여 사용한 죄, 회개로도 씻을 수 없을지니.","JPN":"カルメン。他人の体を略奪し用いた罪、懺悔によっても消せぬ。","ENG":"Carmen. Even though repentance, the sins of plundering and using the body of the other person cannot be washed away.","TWN":"卡門，搶奪他人身體使用的罪孽，就算悔改也無法洗清。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이제 안식을 받아들일 때다.","JPN":"もう安息を受け入れる時だ。","ENG":"It is time you accepted your slumber.","TWN":"如今是時候進入安息了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그새 입이 다시 트이셨나 보네, 예하.","JPN":"またしゃべれるようになったようね、猊下。","ENG":"So you can finally speak again, Eminence.","TWN":"你又開始會說教啦，主教。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"인간들 사이에 섞여 살더니 잊고 지내던 옛날 생각이라도 나는 걸까?","JPN":"人間と共に暮らしながら、忘れていた過去のことでも思い出しちゃったのかしら？","ENG":"Was it because spending time with humans reminded you of the old days?","TWN":"混在人類中間生活，難道讓你想起了遺忘的過去嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"이 몸이 원래 얼마나 근육 투성이였는지 예하는 알까?","JPN":"もともとこの体がどれほど筋肉隆々だったか、猊下はわかってるの？","ENG":"I wonder if you know how burly this body was.","TWN":"主教知道這副身軀本來有多少肌肉嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"내 마음에 들게 가꾸느라 잔뜩 공을 들였어.","JPN":"私の好みにするのに散々苦労したわ。","ENG":"I put so much effort into making it look just the way I like it.","TWN":"為了讓自己滿意，我花了很多心思。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"그러니까…… 함부로 말하지 말아 줄래?","JPN":"だから……知ったような口をきかないでくれる？","ENG":"So... will you please just shut up?","TWN":"所以……不要再亂說好嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"자진하여 위험을 자초하러 나타나셨군요.","JPN":"自ら危険を求めて現れたのですね。","ENG":"You have voluntarily come to risk yourself.","TWN":"你主動出來招惹危險了啊。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"연주는 마음에 드시는지요?","JPN":"演奏はお気に召しましたか？","ENG":"Did you enjoy our performance?","TWN":"演奏你還滿意嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"글쎄. 클래식이 취향이긴 하지만 이 음반은 너무 격렬하군.","JPN":"さあな。確かにクラシックは俺の好みではあるが、このレコードはいささか激しすぎるな。","ENG":"I'm not so sure. I enjoy classical music, but this score is too intense for my tastes.","TWN":"這個嘛，我雖然喜歡古典音樂，但這個唱片太激烈了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"연로하셨어도 기개는 젊은이들에 부럽지 않은 분이군요.","JPN":"年老いてもその気骨は若者に負けませんね。","ENG":"I admire your spirit and how, despite your age, it matches that of young people.","TWN":"你雖然上了年紀，但氣勢還是不輸給年輕人呢。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"허나 땅을 기게 되어도……","JPN":"ですが、地を這うことになっても……","ENG":"But even if you were to crawl on all fours...","TWN":"不過就算是在地上爬……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……음?","JPN":"……ん？","ENG":"Hmm...?","TWN":"……嗯？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L1_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"전 대원, 강하 완료. 연주할 틈을 주지 않게 엄호를 유지하도록.","JPN":"全隊員、降下完了。演奏する暇を与えないよう、援護を維持しろ。","ENG":"Prepare to descend, men. Maintain cover fire and deny them any opportunity to play.","TWN":"全體隊員，降落完畢。請持續掩護，不要讓她們有機會演奏。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"안녕. 다시 볼 생각에 조금 과속해서 왔어, 지휘자 씨.","JPN":"久しぶりね。また会えると思ってちょっと飛ばして来たの、マエストロ。","ENG":"Hi. I came as fast as I could just to see you, Ms. Conductor.","TWN":"你好啊，因為想要再見到你，來的時候我有點超速了呢，指揮家。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지난번처럼 곱상한 꼴로 내빼긴 어렵지 않으려나, 응?","JPN":"この前みたいにお上品に逃げるのは難しいんじゃないかしら、ね？","ENG":"It'll be difficult to get away from me without getting hurt this time, hmm?","TWN":"你不覺得自己很難像上次那樣漂亮抽身了嗎，嗯？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"전대장도, 중사도 기척이 느껴지지 않는군요.","JPN":"戦隊長も、軍曹も気配がありませんね。","ENG":"I do not sense Commander, nor Sergeant.","TWN":"戰隊長，中士，全都沒感覺到動靜呢。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신들만으로 충분하다고 생각한 건가요?","JPN":"あなたたちだけで十分だと思ったのですか？","ENG":"Do you think you all will be enough to stop us?","TWN":"你們以為只憑你們就能贏了我嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"혹은…… 지휘를 무시한 독단일 수도 있겠군요.","JPN":"もしくは……指揮を無視した独断である可能性もありますね。","ENG":"Or... it could be your dogmatic decision that looks down on my conducting.","TWN":"或許……也可能是無視指揮的武斷。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"글쎄, 독단일지 용단일지는 봐야 아는 일이지.","JPN":"どうだろうか。独断なのか勇断なのかは後々わかることだ。","ENG":"Well, you'll find out if it's our being dogmatic or decisive.","TWN":"這個嘛，是武斷還是果斷，要看了才知道。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"음? 접근을……?","JPN":"ん？　接近を……？","ENG":"Hmm? Up close...?","TWN":"嗯？靠近……？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"다가갈 수는 있어도 공격을 받아치는군. 확실히 5종 침식체다워.","JPN":"近づくことはできるが、攻撃は打ち返されるか。さすがは第5種侵食体だ。","ENG":"You still deflect my attacks even if I get close. You definitely are a Category 5 C.O.","TWN":"即使可以靠近也不會受到攻擊，不愧是5類侵蝕體。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그림자를 통해 이동한다, 라…….","JPN":"影を通じて移動する、か……","ENG":"Moving through shadows, huh...","TWN":"通過暗影移動……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"카르멘 말대로 과분한 재능을 가지고 있군요.","JPN":"カルメンから聞いていましたが、身に余る才能を持っていますね。","ENG":"You do have an undeserved talent, as Carmen stated.","TWN":"果然如卡門所說，你擁有高超的才能。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 버넷 형님에게도 돼지 목의 진주란 소리 많이 들었지.","JPN":"はは、バーネットからも豚に真珠とよく言われたものだ。","ENG":"Haha! Burnett used to always say it was like casting pearls before swine.","TWN":"哈哈，伯內特大哥也常說這種才能給我很浪費。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그나저나 예상대로 그 의식인지 때문에 진을 많이 빼신 모양인데……","JPN":"それにしても、予想どおり、その儀式か何かでだいぶ力を使ったようだが……","ENG":"You look tired, as expected. Did that ritual drain a lot of your energy?","TWN":"話說回來，和預想的一樣，你好像因為那個儀式消耗了很多體力……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"멘탈 프린팅은 잠시 잊어 두시지, 연주자 아가씨.","JPN":"今はメンタル・プリンティングについてはないものと考えた方がいい、演奏者のお嬢さん。","ENG":"How about we put aside Mental Printing for a moment, little miss performer?","TWN":"暫時忘掉智力複印吧，演奏者小姐。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};